import React from 'react';
import { motion } from 'framer-motion';
import { X } from 'lucide-react';

const DetailedModal = ({ title, onClose }) => {
  // Highly realistic mock data for the IIT presentation
  const mockDatabase = [
    { type: 'DDoS', attacker: '45.22.11.9', targetIp: '10.0.4.15', targetOrg: 'GovNet Infrastructure', origin: 'Russia', status: 'Blocked by CortexShield' },
    { type: 'Ransomware', attacker: '192.168.1.105', targetIp: '172.16.0.4', targetOrg: 'HealthCare Systems', origin: 'China', status: 'Quarantined' },
    { type: 'Phishing', attacker: '114.55.20.1', targetIp: '192.168.1.50', targetOrg: 'Global Finance Ltd', origin: 'USA', status: 'Email Filtered' },
    { type: 'Port Scan', attacker: '8.8.8.8', targetIp: '10.1.1.20', targetOrg: 'TechCorp India', origin: 'Brazil', status: 'IP Banned' },
    { type: 'Botnet', attacker: '203.0.113.5', targetIp: '172.16.2.11', targetOrg: 'E-Comm Giants', origin: 'Unknown', status: 'Connection Dropped' },
    { type: 'Zero-Day', attacker: '91.221.33.11', targetIp: '10.0.0.5', targetOrg: 'Defense Logistics', origin: 'Russia', status: 'Blocked by CortexShield' },
  ];

  return (
    <div style={{ position: 'fixed', top: 0, left: 0, width: '100%', height: '100%', background: 'rgba(11, 15, 25, 0.9)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 1000 }}>
      <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} style={{ background: '#1a1f2e', padding: '30px', borderRadius: '12px', width: '90%', maxHeight: '80vh', overflowY: 'auto', border: '1px solid #3b82f6', boxShadow: '0 0 30px rgba(59, 130, 246, 0.2)' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px', borderBottom: '1px solid #334155', paddingBottom: '15px' }}>
          <h2 style={{ margin: 0, color: '#00ff9d' }}>Log Viewer: {title}</h2>
          <button onClick={onClose} style={{ background: 'transparent', border: 'none', cursor: 'pointer', color: '#ef4444' }}><X size={28} /></button>
        </div>
        
        <table style={{ width: '100%', textAlign: 'left', borderCollapse: 'collapse', color: 'white', fontSize: '14px' }}>
          <thead>
            <tr style={{ background: '#0b0f19', color: '#94a3b8' }}>
              <th style={{ padding: '12px' }}>Attack Type</th>
              <th style={{ padding: '12px' }}>Attacker IP</th>
              <th style={{ padding: '12px' }}>Location</th>
              <th style={{ padding: '12px' }}>Target Company</th>
              <th style={{ padding: '12px' }}>Target IP</th>
              <th style={{ padding: '12px' }}>Cortex Action</th>
            </tr>
          </thead>
          <tbody>
            {mockDatabase.map((threat, i) => (
              <tr key={i} style={{ borderBottom: '1px solid #334155', transition: 'background 0.3s' }}>
                <td style={{ padding: '15px 12px', color: '#ef4444', fontWeight: 'bold' }}>{threat.type}</td>
                <td style={{ padding: '15px 12px', fontFamily: 'monospace', color: '#cbd5e1' }}>{threat.attacker}</td>
                <td style={{ padding: '15px 12px' }}>{threat.origin}</td>
                <td style={{ padding: '15px 12px', fontWeight: 'bold' }}>{threat.targetOrg}</td>
                <td style={{ padding: '15px 12px', fontFamily: 'monospace', color: '#cbd5e1' }}>{threat.targetIp}</td>
                <td style={{ padding: '15px 12px', color: '#00ff9d' }}>{threat.status}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </motion.div>
    </div>
  );
};

export default DetailedModal;
